export function IconifyComponent(properties) {
  const params = {
    width: properties.width || "1rem",
    height: properties.height || "1rem",
    style: properties.style || "display:inline-block;"
  }
  const index = icons.findIndex(icon => icon.name === properties.name)
  if (index === -1) return icons[0].component(params)
  return icons[index].component(params)
}